// commentKey generates a unique key for looking up comments by file+line+type
func commentKey(filePath string, lineNum int, lineType string) string {
	return fmt.Sprintf("%s:%d:%s", filePath, lineNum, lineType)
}

// buildCommentMap creates a lookup map from review comments
func buildCommentMap(comments []models.ReviewComment) map[string][]models.ReviewComment {
	m := make(map[string][]models.ReviewComment)
	for _, c := range comments {
		key := commentKey(c.FilePath, c.LineNumber, c.LineType)
		m[key] = append(m[key], c)
	}
	return m
}

// lineHasComment checks if a specific line has review comments
func lineHasComment(commentMap map[string][]models.ReviewComment, filePath string, line DiffLine) bool {
	lineNum := line.NewNum
	lt := "new"
	if line.Type == "del" {
		lineNum = line.OldNum
		lt = "old"
	} else if line.Type == "ctx" {
		lt = "ctx"
	}
	if lineNum == 0 {
		return false
	}
	_, ok := commentMap[commentKey(filePath, lineNum, lt)]
	return ok
}

// getLineComments returns comments for a specific line
func getLineComments(commentMap map[string][]models.ReviewComment, filePath string, line DiffLine) []models.ReviewComment {
	lineNum := line.NewNum
	lt := "new"
	if line.Type == "del" {
		lineNum = line.OldNum
		lt = "old"
	} else if line.Type == "ctx" {
		lt = "ctx"
	}
	if lineNum == 0 {
		return nil
	}
	return commentMap[commentKey(filePath, lineNum, lt)]
}

// lineTypeForDiff maps diff line type to review line type
func lineTypeForDiff(diffType string) string {
	switch diffType {
	case "del":
		return "old"
	case "ctx":
		return "ctx"
	default:
		return "new"
	}
}

// lineNumForReview returns the appropriate line number for a review comment
func lineNumForReview(line DiffLine) int {
	if line.Type == "del" {
		return line.OldNum
	}
	return line.NewNum
}

