// SplitPair represents a side-by-side line pair
type SplitPair struct {
	Left  DiffLine
	Right DiffLine
}

func buildSplitLines(lines []DiffLine) []SplitPair {
	var pairs []SplitPair
	var delQueue []DiffLine
	var addQueue []DiffLine

	flushQueues := func() {
		maxLen := len(delQueue)
		if len(addQueue) > maxLen {
			maxLen = len(addQueue)
		}
		for i := 0; i < maxLen; i++ {
			pair := SplitPair{
				Left:  DiffLine{Type: "empty"},
				Right: DiffLine{Type: "empty"},
			}
			if i < len(delQueue) {
				pair.Left = delQueue[i]
			}
			if i < len(addQueue) {
				pair.Right = addQueue[i]
			}
			pairs = append(pairs, pair)
		}
		delQueue = nil
		addQueue = nil
	}

	for _, line := range lines {
		switch line.Type {
		case "del":
			if len(addQueue) > 0 {
				flushQueues()
			}
			delQueue = append(delQueue, line)
		case "add":
			addQueue = append(addQueue, line)
		case "ctx":
			flushQueues()
			pairs = append(pairs, SplitPair{Left: line, Right: line})
		}
	}
	flushQueues()
	return pairs
}

func inlineLineClass(lineType string) string {
	switch lineType {
	case "add":
		return "bg-success/10"
	case "del":
		return "bg-error/10"
	default:
		return ""
	}
}

func splitCellBg(lineType string) string {
	switch lineType {
	case "add":
		return "bg-success/10"
	case "del":
		return "bg-error/10"
	case "empty":
		return "bg-base-200/50"
	default:
		return ""
	}
}

func lineMarker(lineType string) string {
	switch lineType {
	case "add":
		return "+"
	case "del":
		return "-"
	default:
		return " "
	}
}

func diffFileName(path string) string {
	parts := strings.Split(path, "/")
	if len(parts) > 2 {
		return ".../" + strings.Join(parts[len(parts)-2:], "/")
	}
	return path
}

func diffStats(f DiffFile) string {
	adds, dels := 0, 0
	for _, h := range f.Hunks {
		for _, l := range h.Lines {
			if l.Type == "add" {
				adds++
			} else if l.Type == "del" {
				dels++
			}
		}
	}
	return fmt.Sprintf("+%d -%d", adds, dels)
}

func fileCountSuffix(n int) string {
	if n == 1 {
		return ""
	}
	return "s"
}

func diffFileMetrics(f DiffFile) (int, int) {
	totalLines := 0
	totalChars := 0
	for _, h := range f.Hunks {
		totalChars += len(h.Header)
		for _, l := range h.Lines {
			totalLines++
			totalChars += len(l.Content)
		}
	}
	return totalLines, totalChars
}

func buildDiffRenderMetas(files []DiffFile) []DiffFileRenderMeta {
	metas := make([]DiffFileRenderMeta, 0, minInt(len(files), maxDiffFiles))
	cumulativeLines := 0
	cumulativeChars := 0

	for i, f := range files {
		if i >= maxDiffFiles {
			break
		}

		lineCount, charCount := diffFileMetrics(f)
		meta := DiffFileRenderMeta{
			Index:     i,
			File:      f,
			LineCount: lineCount,
			CharCount: charCount,
		}

		switch {
		case lineCount > maxLoadableFileDiffLines || charCount > maxLoadableFileDiffChars:
			meta.BlockedReason = fmt.Sprintf(
				"This file exceeds single-file limit (%d lines or %s raw diff).",
				maxLoadableFileDiffLines,
				formatByteSize(maxLoadableFileDiffChars),
			)
		case cumulativeLines+lineCount > maxLoadableTotalDiffLines || cumulativeChars+charCount > maxLoadableTotalDiffChars:
			meta.BlockedReason = fmt.Sprintf(
				"Total diff load limit reached (%d lines or %s raw diff).",
				maxLoadableTotalDiffLines,
				formatByteSize(maxLoadableTotalDiffChars),
			)
		default:
			cumulativeLines += lineCount
			cumulativeChars += charCount
			if lineCount <= autoLoadFileDiffLines && charCount <= autoLoadFileDiffChars {
				meta.AutoLoad = true
			} else {
				meta.CanLoadOnDemand = true
			}
		}

		metas = append(metas, meta)
	}

	return metas
}

func diffFileCardID(idx int, view string) string {
	if view == "split" {
		return fmt.Sprintf("diff-file-split-%d", idx)
	}
	return fmt.Sprintf("diff-file-%d", idx)
}

func diffFileCardTargetSelector(idx int, view string) string {
	return "#" + diffFileCardID(idx, view)
}

